import { useState } from "react";
import { Link } from "react-router-dom";
import mockUrunListesi from "../mock/mockUrunListesi";
import { Urun } from "../types/Urun";

const kategoriler = [
  {
    baslik: "Cep Telefonu-Aksesuar",
    altKategoriler: ["Apple Telefonlar", "Android Telefonlar"],
  },
  {
    baslik: "Bilgisayar-Tablet",
    altKategoriler: ["Tabletler", "Dizüstü Bilgisayarlar"],
  },
  {
    baslik: "Elektrikli Ev Aletleri",
    altKategoriler: ["Süpürgeler", "Küçük Ev Aletleri"],
  },
];

export default function Kategoriler() {
  const [acilan, setAcilan] = useState<string | null>(null);

  return (
    <div className="mt-4 border-y py-2">
      {/* Üst Menü */}
      <div className="flex gap-6 overflow-x-auto whitespace-nowrap">
        {kategoriler.map((kat, i) => (
          <div
            key={i}
            onMouseEnter={() => setAcilan(kat.baslik)}
            onMouseLeave={() => setAcilan(null)}
            className="cursor-pointer font-semibold hover:text-yellow-600 px-2 relative"
          >
            {kat.baslik}
          </div>
        ))}
      </div>

      {/* Alt Menü */}
      {acilan && (
        <div className="mt-4 p-4 bg-gray-100 border rounded grid sm:grid-cols-2 md:grid-cols-3 gap-6 transition-all duration-300">
          {kategoriler
            .find((k) => k.baslik === acilan)
            ?.altKategoriler.map((alt, j) => {
              const altUrunler = mockUrunListesi
                .filter((u: Urun) => u.kategori.toLowerCase() === alt.toLowerCase())
                .slice(0, 2);
              return (
                <div key={j}>
                  <h4 className="font-semibold text-blue-600 mb-2">{alt}</h4>
                  <ul className="space-y-1 text-sm text-gray-700">
                    {altUrunler.length === 0 ? (
                      <li className="text-gray-400">Ürün yok</li>
                    ) : (
                      altUrunler.map((urun) => (
                        <li key={urun.id}>
                          <Link
                            to={`/urun/${urun.id}`}
                            className="hover:text-blue-600 hover:underline"
                          >
                            {urun.ad}
                          </Link>
                        </li>
                      ))
                    )}
                  </ul>
                  <Link
                    to={`/kategori/${alt.toLowerCase()}`}
                    className="text-xs text-blue-500 hover:underline mt-1 inline-block"
                  >
                    Tümünü Gör
                  </Link>
                </div>
              );
            })}
        </div>
      )}
    </div>
  );
}
